INSERT INTO public.question_groups (id, payload, group_number, part_id, section_id, exam_id) VALUES ('8edce4be-5362-413f-af69-3d5d5a7d089c', '{"title": "My city", "content": "I live in the centre of London. I love it because there''s always something happening and there are people around whatever time it is. Famous people like it too – they often come here for the restaurants and shops.\n\nI''ve lived here all my life. When I was little, I had singing lessons at a place near where I live now. I was afraid of the teacher at first, and some of the songs we did together were quite hard to learn. But she was good at what she did and I learned a lot of things that have helped me in my career.\n\nWhen friends visit me now, I enjoy taking them sightseeing. You can get a bus around the city, but we prefer to walk. I''ve got a little car and I love driving, but there''s so much traffic here, and it''s hard to find parking spaces.\n\nOne building I love is the Natural History Museum. They sometimes hold parties there, and last December my band and I played at one. I''ll never forget it. When I go to exhibitions at the museum with my friends, I tell them all about that night and how amazing it was.\n\nSoon I''ll be leaving London to go on tour with my band. We''re playing in lots of new cities and I can''t wait to explore them. We''ve sold lots of tickets, which is great. I''ll be away from my family for six months, but they''re coming to see me sing, so it''s fine.", "imageUrl": "", "subtitle": ""}', 1, '3', null, '8afa8214-bc17-4d6f-bea5-7c9b74668c62');
INSERT INTO public.question_groups (id, payload, group_number, part_id, section_id, exam_id) VALUES ('c1fc42a5-9a5d-47d6-9ea5-c8fe9bec581b', '{"title": "For each question, choose the correct answer.", "content": "Camels are one of the only large animals that can live happily in the Sahara Desert. The hot weather and strong winds are not a (19)____ for them. Also, they do not need to eat or drink every day, and this (20)____ them very useful to the people who live there.\n\nCamels begin working at the age of about four years old and don''t stop until they are around 25 to 30. They can carry people or things a very long (21)____, and because of this they are sometimes (22)____ the ''ships of the desert''.\n\nThese days, there are roads across some (23)____ of the Sahara, so buses and lorries are often (24)____. However, in places where there are no roads, camels are still the only type of transport.", "imageUrl": "", "subtitle": ""}', 1, '4', null, '8afa8214-bc17-4d6f-bea5-7c9b74668c62');
INSERT INTO public.question_groups (id, payload, group_number, part_id, section_id, exam_id) VALUES ('ee91811e-25bc-4592-8ab1-93cd209c11d1', '{"title": "You will hear a man talking about a film on local radio.", "content": "", "imageUrl": "", "subtitle": ""}', 1, '9', null, '8afa8214-bc17-4d6f-bea5-7c9b74668c62');
INSERT INTO public.question_groups (id, payload, group_number, part_id, section_id, exam_id) VALUES ('826216e9-ff4c-4a3f-b499-036cd45dd941', '{"options": [{"answer": "comfortable beds", "content": "", "imageUrl": ""}, {"answer": "expensive", "content": "", "imageUrl": ""}, {"answer": "friendly staff", "content": "", "imageUrl": ""}, {"answer": "good food", "content": "", "imageUrl": ""}, {"answer": "hard to find", "content": "", "imageUrl": ""}, {"answer": "large bedrooms", "content": "", "imageUrl": ""}, {"answer": "no parking", "content": "", "imageUrl": ""}, {"answer": "noisy", "content": "", "imageUrl": ""}]}', 1, '12', null, '8afa8214-bc17-4d6f-bea5-7c9b74668c62');
INSERT INTO public.question_groups (id, payload, group_number, part_id, section_id, exam_id) VALUES ('17e0bcac-0f27-4e9f-bfac-e9fadad97ebf', '{"title": "Learning for fun", "content": "Paula\nI work full time as a nurse, and don’t have much time for hobbies, but I’ve been interested in photography since I was a child. On my last holiday to India, I took lots of pictures, and everyone I showed them to said they were great. So I decided to do a course. At first, I was afraid I might not be good enough. After all, it was my first time as a student for ten years! But I loved it from the very first lesson.\n\nSally\nWhen I was still at school, I started learning the violin. It was fun and I was quite good at it, but I didn’t do it for long, because I had so many other hobbies. Then last year, I was having a hard time in my job, and my husband bought me a violin as a present. I started learning with a teacher again. All three of my children are learning to play instruments too, so now we can practise with each other!\n\nKim\nLast year I moved to a new city because of my job. I didn’t have anything to do in the evenings, so one of my colleagues said I should try a class at the local college. I immediately thought of cooking. My mum was a fantastic cook, and when I was a child I loved watching her in the kitchen, but I never learned how to cook myself. The other students on the course are around my age, and sometimes we go to restaurants together, or even the cinema.", "imageUrl": "questions/images/1777015426968_c53f2068_gn_q2_2025_rw_p2_1.png", "subtitle": "Meet three women who enjoy taking classes in their free time."}', 1, '2', null, '8afa8214-bc17-4d6f-bea5-7c9b74668c62');
